AUTHORIZATION.example:
@app.route('/api/orders/<order_id>')
@jwt_required()
def get_order(order_id):
    user_id = get_jwt_identity()
    order = db.query(Order).filter_by(id=order_id).first()
    if not order:
        return jsonify({"error": "Not Found"}), 404
    # Validazione autorizzazione
    if order.user_id != user_id:
        return jsonify({"error": "Forbidden"}), 403
    return jsonify(order.to_dict())

AUTHENTICATION.example:
# Proteggere l'applicazione Flask caricando un decorator di validazione token
@app.route('/api/profile')
@jwt_required()
def get_profile():
    # Identità del possessore del token confermata dall'Header Authorization Bearer
    current_user = get_jwt_identity()
    return jsonify(db.get_user(current_user))

